namespace sv_3154825d11474a23a996fd3a31aed9c4.Services;

/// <summary>
/// Scoped service (per-circuit) that tracks the low-stock alert count for the
/// currently selected warehouse. Fires <see cref="OnChange"/> so every
/// subscribed component re-renders when new data arrives.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int LowStockCount { get; private set; }

    /// <summary>Raised after <see cref="RefreshAsync"/> updates the count.</summary>
    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items below
    /// minimum stock levels in the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Fetches the latest count and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LowStockCount = await GetLowStockCountAsync(warehouseId);
        OnChange?.Invoke();
    }
}

