@code {
    private Action? _handler;

    private string BadgeClass => AlertService.LowStockCount > 0 ? "bg-danger" : "bg-secondary";

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because RefreshAsync fires OnChange from a
        // timer callback â€” outside the Blazor sync context.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

