@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@implements IDisposable
@using sv_3154825d11474a23a996fd3a31aed9c4.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">
            đź“¦ @_warehouseName
        </h5>
        <p class="card-text">
            Low-stock items:
            <span class="badge rounded-pill @BadgeClass fs-6">@AlertService.LowStockCount</span>
        </p>
        <p class="text-muted small mb-0">Refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _warehouseName = string.Empty;
    private string _warehouseId = string.Empty;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _handler;

    private string BadgeClass => AlertService.LowStockCount > 0 ? "bg-danger" : "bg-secondary";

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        var id = Warehouse?.WarehouseId ?? "WH-A";
        var name = Warehouse?.DisplayName ?? "Warehouse A";

        if (id != _warehouseId)
        {
            _warehouseId = id;
            _warehouseName = name;

            // Restart polling for the newly selected warehouse.
            await StopPollingAsync();
            await AlertService.RefreshAsync(_warehouseId);
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                // RefreshAsync updates the count and fires OnChange,
                // which notifies ALL subscribed components (sidebar badge, etc.).
                await AlertService.RefreshAsync(_warehouseId);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / warehouse switch.
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

